const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    question: body.question || 'Vue nationale des indicateurs epidemiologiques 2023',
    region: body.region || 'National',
    type_rapport: body.type_rapport || 'botpress',
    user_id: body.user_id || 'anonymous'
  }
}];

const indicateurs = $('Lire Indicateurs').all().map(i => i.json);
const alertes = $('Lire Alertes').all().map(i => i.json);
const regional = $('Lire Vue Regionale').all().map(i => i.json);
const params = $('Extraire parametres').first().json;

const snap_ind = indicateurs
  .filter(r => r.Maladie)
  .map(r => `${r.Maladie} | ${r.Indicateur} | 2023: ${r['2023']} | Seuil OMS: ${r['Seuil OMS']} | Statut: ${r['Statut 2023']}`)
  .join('\n');

const snap_alertes = alertes
  .filter(r => r.Maladie)
  .map(r => `${r.Maladie} — ${r['Valeur Maroc 2023']} vs seuil ${r['Seuil OMS']} → ${r['Niveau Criticité']} | ${r['Recommandation OMS']}`)
  .join('\n');

const snap_reg = regional
  .filter(r => r.Région && r.Région !== 'NOTE')
  .map(r => `${r.Région} | Diabète: ${r['Diabète — Prévalence (%)']}% | TB: ${r['Tuberculose — Incidence (/100k)']}/100k`)
  .join('\n');

return [{
  json: {
    question: params.question,
    region: params.region,
    type_rapport: params.type_rapport,
    user_id: params.user_id,
    snapshot_indicateurs: snap_ind,
    snapshot_alertes: snap_alertes,
    snapshot_regional: snap_reg
  }
}];
